package eu.gridverse.srv.computation.services.config;
import eu.gridverse.powsbl.loadflow.LoadFlowAdapter; import eu.gridverse.powsbl.security.SecurityAnalysisAdapter; import eu.gridverse.powsbl.sensitivity.SensitivityAnalysisAdapter; import eu.gridverse.srv.computation.services.service.ComputationService;
import org.springframework.context.annotation.Bean; import org.springframework.context.annotation.Configuration; import org.springframework.web.servlet.config.annotation.ResourceHandlerRegistry; import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;
@Configuration public class ComputationConfiguration implements WebMvcConfigurer { @Bean ComputationService computationService(LoadFlowAdapter lf, SecurityAnalysisAdapter sa, SensitivityAnalysisAdapter sn) { return new ComputationService(lf, sa, sn); } @Override public void addResourceHandlers(ResourceHandlerRegistry registry){registry.addResourceHandler("/openapi/**").addResourceLocations("classpath:/openapi/");} }
